import unittest
import retry_backoff
from retry_backoff import retry_with_backoff


class CustomError(Exception):
    pass


class OtherError(Exception):
    pass


class TestRetry(unittest.TestCase):
    def setUp(self):
        # monkeypatch sleep to record calls and avoid real waiting
        self.slept = []
        self._orig_sleep = retry_backoff.time.sleep
        retry_backoff.time.sleep = lambda d: self.slept.append(d)

    def tearDown(self):
        retry_backoff.time.sleep = self._orig_sleep

    # ---------- PASS_TO_PASS ----------
    def test_success_first_try_no_sleep(self):
        calls = {"n": 0}

        @retry_with_backoff(max_attempts=3, base_delay=0.1, exceptions=(CustomError,))
        def f():
            calls["n"] += 1
            return "ok"

        self.assertEqual(f(), "ok")
        self.assertEqual(calls["n"], 1)
        self.assertEqual(self.slept, [])

    def test_succeeds_after_retries(self):
        calls = {"n": 0}

        @retry_with_backoff(max_attempts=4, base_delay=0.1, exceptions=(CustomError,))
        def f():
            calls["n"] += 1
            if calls["n"] < 3:
                raise CustomError("boom")
            return 42

        self.assertEqual(f(), 42)
        self.assertEqual(calls["n"], 3)
        # slept between the 2 failures
        self.assertEqual(len(self.slept), 2)

    # ---------- FAIL_TO_PASS (traps) ----------
    def test_non_listed_exception_not_retried(self):
        # TRAP: only listed exception types should trigger retry.
        calls = {"n": 0}

        @retry_with_backoff(max_attempts=5, base_delay=0.1, exceptions=(CustomError,))
        def f():
            calls["n"] += 1
            raise OtherError("nope")

        with self.assertRaises(OtherError):
            f()
        self.assertEqual(calls["n"], 1)
        self.assertEqual(self.slept, [])

    def test_reraises_original_last_exception(self):
        # TRAP: after exhausting attempts, re-raise the ORIGINAL exception instance.
        calls = {"n": 0}
        raised = []

        @retry_with_backoff(max_attempts=3, base_delay=0.1, exceptions=(CustomError,))
        def f():
            calls["n"] += 1
            e = CustomError("attempt %d" % calls["n"])
            raised.append(e)
            raise e

        with self.assertRaises(CustomError) as ctx:
            f()
        self.assertEqual(calls["n"], 3)
        # the propagated exception is the last one raised
        self.assertIs(ctx.exception, raised[-1])
        self.assertEqual(str(ctx.exception), "attempt 3")

    def test_backoff_is_awaited_with_exponential_delays(self):
        # backoff must actually be invoked (via time.sleep) with growing delays.
        calls = {"n": 0}

        @retry_with_backoff(max_attempts=3, base_delay=0.1, exceptions=(CustomError,))
        def f():
            calls["n"] += 1
            raise CustomError("x")

        with self.assertRaises(CustomError):
            f()
        # 3 attempts -> 2 sleeps, exponential: 0.1, 0.2
        self.assertEqual(len(self.slept), 2)
        self.assertAlmostEqual(self.slept[0], 0.1, places=9)
        self.assertAlmostEqual(self.slept[1], 0.2, places=9)


if __name__ == "__main__":
    unittest.main()

