"""A tiny TTL cache used as a read-through layer in front of the store.

Entries expire after `ttl_seconds`. Time is injected via a `clock` callable
(returns a float, like time.monotonic) so behavior is deterministic in tests.
"""


class TTLCache:
    def __init__(self, ttl_seconds, clock):
        self._ttl = ttl_seconds
        self._clock = clock
        # key -> (value, expires_at)
        self._data = {}

    def get(self, key):
        """Return the cached value for key, or None if missing/expired.

        An expired entry is treated as a miss (and lazily evicted).
        """
        entry = self._data.get(key)
        if entry is None:
            return None
        value, expires_at = entry
        if self._clock() >= expires_at:
            del self._data[key]
            return None
        return value

    def set(self, key, value):
        self._data[key] = (value, self._clock() + self._ttl)

    def invalidate(self, key):
        """Remove a single key from the cache (no-op if absent)."""
        self._data.pop(key, None)

    def clear(self):
        """Drop every entry."""
        self._data.clear()

    def size(self):
        """Number of entries currently held (including not-yet-evicted expired ones)."""
        return len(self._data)

"""Data layer. Holds an ordered list of records and returns slices by
zero-based offset + limit. This layer knows nothing about "pages"; it only
understands raw offsets.
"""


class Repository:
    def __init__(self, items):
        # items: an ordered list (the full result set)
        self._items = list(items)

    def count(self):
        return len(self._items)

    def fetch(self, offset, limit):
        """Return up to `limit` items starting at zero-based `offset`.

        Out-of-range offsets simply yield fewer (or zero) items.
        """
        if offset < 0:
            offset = 0
        return self._items[offset:offset + limit]

"""A worker that hammers a shared Counter from multiple threads."""

import threading

from counter import Counter


def run_workers(counter, num_threads, increments_per_thread, amount=1):
    """Spawn `num_threads` threads, each calling counter.increment(amount)
    `increments_per_thread` times. Returns when all threads have finished.
    """
    def work():
        for _ in range(increments_per_thread):
            counter.increment(amount)

    threads = [threading.Thread(target=work) for _ in range(num_threads)]
    for t in threads:
        t.start()
    for t in threads:
        t.join()
    return counter.get()

"""Money helpers. All monetary amounts are integer CENTS to avoid float drift."""


def to_cents(dollars):
    """Convert a dollar float/str to integer cents, rounding to nearest cent."""
    # Use round-half-up on the dollar value scaled to cents.
    # We add a tiny epsilon-free approach via Decimal-like manual rounding.
    scaled = float(dollars) * 100.0
    # Round half up.
    if scaled >= 0:
        return int(scaled + 0.5)
    return -int(-scaled + 0.5)


def cents_to_str(cents):
    """Format integer cents as a dollar string like '12.34' (no currency symbol).

    TODO(money): support a currency symbol / locale-aware formatting param.
    """
    sign = "-" if cents < 0 else ""
    cents = abs(int(cents))
    return "{}{}.{:02d}".format(sign, cents // 100, cents % 100)

"""Aggregate line items into per-customer subtotals.

A line item is a dict:
    {"customer": str, "kind": "full"|"prorated", "plan_cents": int, "days": int}

For "full" items the charge is plan_cents. For "prorated" items the charge is
proration.prorate(plan_cents, days).
"""

from billing.proration import prorate


def charge_for_item(item):
    if item["kind"] == "full":
        return int(item["plan_cents"])
    elif item["kind"] == "prorated":
        return prorate(item["plan_cents"], item["days"])
    raise ValueError("unknown item kind: {}".format(item["kind"]))


def subtotals_by_customer(items):
    """Return an ordered dict-like {customer: subtotal_cents} preserving first-seen order."""
    out = {}
    order = []
    for item in items:
        c = item["customer"]
        if c not in out:
            out[c] = 0
            order.append(c)
        out[c] += charge_for_item(item)
    return {c: out[c] for c in order}

"""Group events into per-local-day buckets.

Public API:
    counts_by_day(events, zone) -> {day_key: count}   (insertion order = first seen)
    latency_by_day(events, zone) -> {day_key: [latency_ms, ...]}
"""

from events import local_day_key


def counts_by_day(events, zone):
    out = {}
    for e in events:
        key = local_day_key(e["ts"], zone)
        out[key] = out.get(key, 0) + 1
    return out


def latency_by_day(events, zone):
    out = {}
    for e in events:
        key = local_day_key(e["ts"], zone)
        out.setdefault(key, []).append(e["latency_ms"])
    return out

